#### **任务 1: WebSocket 安全加固**
**工作量**: 1 天 | **文件**: `src/dashboard/server.ts`

```typescript
// 实现清单：
- [ ] 添加 JWT Token 验证
- [ ] 启用 WSS (TLS) 连接
- [ ] 实现 Origin 验证
- [ ] 添加消息签名验证
- [ ] 实现心跳超时机制（30秒）
```

**代码实现**:
```typescript
// src/dashboard/server.ts

// 1. JWT 验证函数
import jwt from 'jsonwebtoken'

function validateToken(token: string): boolean {
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET || 'secret')
    return decoded && decoded.iss === 'ai-dev-team'
  } catch {
    return false
  }
}

// 2. WebSocket 路由增强
fastify.get('/api/ws', { 
  websocket: true,
  onRequest: async (request, reply) => {
    // Origin 验证
    const origin = request.headers.origin
    if (origin !== config.corsOrigin) {
      reply.code(403).send('Forbidden origin')
      return
    }

    // Token 验证
    const token = request.query.token || request.headers['sec-websocket-protocol']
    if (!token || !validateToken(token)) {
      reply.code(401).send('Unauthorized')
      return
    }
  }
}, (connection, req) => {
  // WebSocket 处理逻辑
})
```

