#### **任务 5: RealtimeService 完善**
**工作量**: 1.5 天 | **文件**: `src/dashboard/services/realtime.service.ts`

```typescript
// src/dashboard/services/realtime.service.ts

import { EventEmitter } from 'events'
import { pino } from 'pino'

export class RealtimeService extends EventEmitter {
  private clients: Set<any> = new Set()
  private subscriptions: Map<any, Set<string>> = new Map()
  private heartbeatInterval?: NodeJS.Timeout

  constructor(private logger: pino.Logger) {
    super()
  }

  // 添加客户端
  addClient(socket: any) {
    this.clients.add(socket)
    this.subscriptions.set(socket, new Set(['all']))
    this.logger.info({ clientCount: this.clients.size }, 'Client added')
  }

  // 移除客户端
  removeClient(socket: any) {
    this.clients.delete(socket)
    this.subscriptions.delete(socket)
    this.logger.info({ clientCount: this.clients.size }, 'Client removed')
  }

  // 订阅频道
  subscribe(socket: any, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.add(channel)
      this.logger.info({ channel, clientCount: this.clients.size }, 'Client subscribed')
    }
  }

  // 取消订阅
  unsubscribe(socket: any, channel: string) {
    const channels = this.subscriptions.get(socket)
    if (channels) {
      channels.delete(channel)
    }
  }

  // 广播消息（核心方法）
  async broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data })

    this.clients.forEach(client => {
      if (client.readyState === 1) { // WebSocket.OPEN
        try {
          client.send(message)
        } catch (error) {
          this.logger.error(error, 'Failed to send message to client')
          this.removeClient(client)
        }
      }
    })
  }

  // 专用广播方法
  async broadcastIterationStatus(data: any) {
    await this.broadcast('iteration.status_changed', data)
  }

  async broadcastAgentStatus(data: any) {
    await this.broadcast('agent.status_changed', data)
  }

  async broadcastProgress(data: any) {
    await this.broadcast('iteration.progress', data)
  }

  async broadcastMetrics(data: any) {
    await this.broadcast('system.metrics', data)
  }

  // 心跳检测
  startHeartbeat(intervalMs: number = 30000) {
    this.heartbeatInterval = setInterval(() => {
      const message = JSON.stringify({ event: 'ping', timestamp: Date.now() })
      this.clients.forEach(client => {
        if (client.readyState === 1) {
          client.send(message)
        }
      })
    }, intervalMs)
  }

  handlePong(socket: any) {
    this.logger.debug('Received pong from client')
  }

  // 清理
  destroy() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval)
    }
    this.clients.clear()
    this.subscriptions.clear()
  }
}
```

