  // utils/retry.ts
  export async function retryWithBackoff<T>(
    fn: () => Promise<T>,
    maxRetries: number = 3,
    baseDelay: number = 1000
  ): Promise<T> {
    for (let i = 0; i < maxRetries; i++) {
      try {
        return await fn()
      } catch (error) {
        if (i === maxRetries - 1) throw error
        await sleep(baseDelay * Math.pow(2, i))
      }
    }
    throw new Error('重试失败')
  }
  ```

