### 8. **WebSocket 无心跳超时** 🟡
**位置**: `src/dashboard/services/realtime.service.ts`

**修复**:
```typescript
export class RealtimeService {
  private heartbeatInterval: NodeJS.Timeout;
  private clientTimeouts: Map<WebSocket, NodeJS.Timeout> = new Map();

  startHeartbeat(interval: number = 30000) {
    this.heartbeatInterval = setInterval(() => {
      this.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
          client.send(JSON.stringify({ event: 'ping', timestamp: Date.now() }));

          // 设置超时检测
          const timeout = setTimeout(() => {
            this.removeClient(client);
            logger.warn('Client timeout, disconnected');
          }, interval * 2);

          this.clientTimeouts.set(client, timeout);
        }
      });
    }, interval);
  }
}
```

