// src/dashboard/integration/iteration-event-emitter.ts
import { EventEmitter } from 'events';

/**
 * 迭代事件发射器
 * 用于连接 AutoIterationEngine 和 Dashboard
 */
export class IterationEventEmitter extends EventEmitter {
  private static instance: IterationEventEmitter;

  static getInstance() {
    if (!this.instance) {
      this.instance = new IterationEventEmitter();
    }
    return this.instance;
  }

  // 定义事件类型
  emitIterationStart(data: IterationStartData) {
    this.emit('iteration.start', data);
  }

  emitIterationProgress(data: IterationProgressData) {
    this.emit('iteration.progress', data);
  }

  emitIterationComplete(data: IterationCompleteData) {
    this.emit('iteration.complete', data);
  }

  emitAgentStatus(data: AgentStatusData) {
    this.emit('agent.status', data);
  }

  emitLogEntry(data: LogData) {
    this.emit('log.entry', data);
  }
}
```

