### **阶段3: 完善RealtimeService** (Day 2, 4小时)

```typescript
// src/dashboard/services/realtime.service.ts
import { IterationEventEmitter } from '../integration/iteration-event-emitter';

export class RealtimeService {
  private eventEmitter: IterationEventEmitter;

  constructor() {
    this.eventEmitter = IterationEventEmitter.getInstance();
    this.setupEventListeners();
  }

  private setupEventListeners() {
    // 监听迭代事件
    this.eventEmitter.on('iteration.start', (data) => {
      this.broadcast('iteration.status_changed', {
        status: 'running',
        ...data
      });
    });

    this.eventEmitter.on('iteration.progress', (data) => {
      this.broadcast('iteration.progress', data);
    });

    this.eventEmitter.on('agent.status', (data) => {
      this.broadcast('agent.status_changed', data);
    });

    this.eventEmitter.on('log.entry', (data) => {
      this.broadcast('log.entry', data);
    });
  }

  // 实现缺失的方法
  broadcast(event: string, data: any) {
    // 推送给所有WebSocket客户端
    this.server.websocket.clients.forEach(client => {
      if (client.socket.readyState === 1) { // OPEN
        client.socket.send(JSON.stringify({ event, data }));
      }
    });
  }
}
```

