```typescript
// 在 AutoIterationEngine 类中添加
private dashboardServices?: any;

async setDashboardIntegration(enabled: boolean) {
  if (!enabled) return;

  try {
    const { getServices } = await import('./dashboard/server');
    this.dashboardServices = getServices();
    console.log('✅ Dashboard integration enabled');
  } catch (error) {
    console.warn('⚠️  Dashboard not available:', error.message);
  }
}

// 在迭代开始时通知
private async notifyIterationStart(iteration: number, requirement: string) {
  if (!this.dashboardServices) return;

  const iteration = await this.dashboardServices.iterationService.create({
    iterationNumber: iteration,
    status: 'running',
    requirement: requirement,
    startedAt: new Date()
  });

  this.dashboardServices.realtimeService.broadcastIterationStatusChange({
    iterationId: iteration.id,
    iterationNumber: iteration,
    status: 'running',
    timestamp: new Date()
  });
}

// 在 Agent 执行时更新进度
private async notifyAgentProgress(agentName: string, progress: number, currentTask: string) {
  if (!this.dashboardServices) return;

  this.dashboardServices.agentService.updateProgress(
    this.currentIterationId,
    agentName,
    progress,
    currentTask
  );

  this.dashboardServices.realtimeService.broadcastAgentStatusChange({
    iterationId: this.currentIterationId,
    agentName,
    agentType: this.getAgentType(agentName),
    status: 'running',
    progress,
    timestamp: new Date()
  });
}

// 在迭代完成时通知
private async notifyIterationComplete(result: IterationResult) {
  if (!this.dashboardServices) return;

  this.dashboardServices.iterationService.update(this.currentIterationId, {
    status: result.status,
    completedAt: new Date(),
    result: result.message
  });
}
```

