### 10. **数据库文件权限未设置** 🟡
**位置**: `src/dashboard/models/index.ts:16-24`

```typescript
export function initDatabase(dbPath: string): Database.Database {
  const dbDir = path.dirname(dbPath);
  if (!fs.existsSync(dbDir)) {
    fs.mkdirSync(dbDir, { recursive: true }); // ❌ 默认权限 0777
  }
  const db = new Database(dbPath); // ❌ 文件权限未设置
}
```

**问题**:
- 数据库文件可能被其他进程读取
- 敏感数据（迭代记录、系统指标）可能泄露
- 缺少文件加密

**风险等级**: 🟡 **Medium**

**修复建议**:

```typescript
import { chmodSync } from 'fs';
import { constants } from 'fs';

export function initDatabase(dbPath: string): Database.Database {
  const dbDir = path.dirname(dbPath);
  if (!fs.existsSync(dbDir)) {
    fs.mkdirSync(dbDir, { 
      recursive: true,
      mode: 0o700 // 仅所有者可访问
    });
  }

  const db = new Database(dbPath);

  // 设置数据库文件权限
  chmodSync(dbPath, 0o600); // 仅所有者可读写

  // 启用加密（可选）
  db.pragma('key = ' + process.env.DB_ENCRYPTION_KEY);
  db.pragma('cipher_memory_security = ON');

  return db;
}
```

