```typescript
// 敏感信息过滤
function sanitizeHistory(history: HistoryEntry[]): HistoryEntry[] {
  const sensitivePatterns = [
    /sk-ant-[a-zA-Z0-9_-]{32,}/g,
    /password["\s:=]+[^\s"']+/gi,
    /api[_-]?key["\s:=]+[^\s"']+/gi
  ];

  return history.map(entry => ({
    ...entry,
    content: entry.content.replace(
      sensitivePatterns,
      '[REDACTED]'
    )
  }));
}

// 设置文件权限
chmodSync(this.historyFile, 0o600);
```

