##### 3.1 AutoIterationEngine集成 (1天)
```typescript
// src/auto-iteration.ts

import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices?: any;

  async initializeDashboard() {
    try {
      this.dashboardServices = getServices();
      this.logger.info('Dashboard services initialized');
    } catch (error) {
      this.logger.warn('Dashboard not available: %s', error.message);
    }
  }

  // 迭代开始时通知
  async notifyIterationStart(iteration: Iteration) {
    if (!this.dashboardServices) return;

    await this.dashboardServices.iterationService.create({
      iterationNumber: iteration.number,
      status: 'running',
      requirement: iteration.requirement
    });

    this.dashboardServices.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      status: 'running',
      timestamp: new Date()
    });
  }

  // 迭代进度更新
  async notifyProgress(progress: number, phase: string) {
    if (!this.dashboardServices) return;

    this.dashboardServices.realtimeService.broadcastIterationProgress({
      progress,
      phase,
      timestamp: new Date()
    });
  }

  // Agent状态变化
  async notifyAgentStatus(agentName: string, status: string) {
    if (!this.dashboardServices) return;

    this.dashboardServices.realtimeService.broadcastAgentStatusChange({
      agentName,
      status,
      timestamp: new Date()
    });
  }

  // 迭代完成
  async notifyIterationComplete(iteration: Iteration, result: any) {
    if (!this.dashboardServices) return;

    await this.dashboardServices.iterationService.update(iteration.id, {
      status: result.success ? 'completed' : 'failed',
      durationSeconds: result.duration,
      commitHash: result.commitHash,
      commitMessage: result.commitMessage
    });

    this.dashboardServices.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      status: result.success ? 'completed' : 'failed',
      timestamp: new Date()
    });
  }
}
```

