// src/agents/base-agent.ts

export class BaseAgent {
  private timeoutMs: number = 5 * 60 * 1000; // 5分钟默认
  private timeoutTimer?: NodeJS.Timeout;

  async execute(input: string): Promise<string> {
    // 设置超时
    this.timeoutTimer = setTimeout(() => {
      throw new Error(`Agent ${this.name} execution timeout`);
    }, this.timeoutMs);

    try {
      const result = await this.process(input);
      clearTimeout(this.timeoutTimer);
      return result;
    } catch (error) {
      clearTimeout(this.timeoutTimer);
      throw error;
    }
  }

  // 支持自定义超时
  setTimeout(ms: number) {
    this.timeoutMs = ms;
  }
}
```

##### 4.2 错误处理增强 (1天)
```typescript
// src/utils/error-handler.ts

export class ErrorHandler {
  static async handleWithRetry<T>(
    fn: () => Promise<T>,
    options: {
      maxRetries?: number;
      backoffMs?: number;
      onRetry?: (error: Error, attempt: number) => void;
    } = {}
  ): Promise<T> {
    const { maxRetries = 3, backoffMs = 1000, onRetry } = options;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error) {
        if (attempt === maxRetries) {
          throw error;
        }

        onRetry?.(error as Error, attempt);
        await this.sleep(backoffMs * attempt); // 指数退避
      }
    }

    throw new Error('Max retries exceeded');
  }

  private static sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}
```

