import { encrypt, decrypt } from './crypto-utils';
import fs from 'fs';
import path from 'path';

interface CredentialStore {
  apiKey: string;
  databaseUrl: string;
  webhookSecret?: string;
}

export class CredentialManager {
  private credentials: CredentialStore | null = null;
  private keyPath: string;

  constructor(keyPath: string = '.credentials') {
    this.keyPath = path.join(process.cwd(), keyPath);
  }

  /**
   * 从加密文件加载凭证
   */
  async loadCredentials(): Promise<CredentialStore> {
    if (this.credentials) {
      return this.credentials;
    }

    try {
      const encrypted = fs.readFileSync(this.keyPath, 'utf-8');
      const decrypted = decrypt(encrypted, this.getMachineKey());
      this.credentials = JSON.parse(decrypted);

      // 内存中安全存储
      this.zeroBuffer(encrypted);

      return this.credentials;
    } catch (error) {
      throw new Error('Failed to load credentials');
    }
  }

  /**
   * 保存加密凭证
   */
  async saveCredentials(credentials: CredentialStore): Promise<void> {
    const json = JSON.stringify(credentials);
    const encrypted = encrypt(json, this.getMachineKey());

    // 设置严格权限
    fs.writeFileSync(this.keyPath, encrypted, { mode: 0o600 });

    this.zeroBuffer(json);
    this.credentials = credentials;
  }

  /**
   * 获取机器特定密钥
   */
  private getMachineKey(): string {
    const machineId = process.env.MACHINE_ID || 
                     require('node-machine-id').machineIdSync();
    return process.env.ENCRYPTION_KEY || machineId;
  }

  /**
   * 清除内存中的敏感数据
   */
  private zeroBuffer(data: string): void {
    // 实际实现需要使用 Buffer.fill(0)
