```typescript
// src/dashboard/middleware/cors-middleware.ts
import { FastifyRequest } from 'fastify';

interface CorsConfig {
  allowedOrigins: string[];
  allowedMethods: string[];
  allowedHeaders: string[];
  credentials: boolean;
  maxAge: number;
}

const PROD_CORS_CONFIG: CorsConfig = {
  allowedOrigins: [
    'https://dashboard.example.com',
    'https://yourdomain.com'
  ],
  allowedMethods: ['GET', 'POST', 'PATCH', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
  maxAge: 86400
};

const DEV_CORS_CONFIG: CorsConfig = {
  allowedOrigins: [
    'http://localhost:5173',
    'http://localhost:3000',
    'http://127.0.0.1:5173'
  ],
  allowedMethods: ['GET', 'POST', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true,
  maxAge: 86400
};

/**
 * 验证 Origin 是否在白名单中
 */
function isOriginAllowed(origin: string | undefined, allowed: string[]): boolean {
  if (!origin) return false;

  return allowed.some(allowedOrigin => {
    // 支持通配符
    if (allowedOrigin === '*') return true;

    // 精确匹配
    if (allowedOrigin === origin) return true;

    // 域名匹配 (https://*.example.com)
    if (allowedOrigin.includes('*')) {
      const pattern = allowedOrigin.replace(/\*/g, '[^.]+');
      const regex = new RegExp(`^${pattern}$`);
      return regex.test(origin);
    }

    return false;
  });
}

/**
 * CORS 中间件工厂
 */
export function createCorsMiddleware(isProduction: boolean) {
  const config = isProduction ? PROD_CORS_CONFIG : DEV_CORS_CONFIG;

  return async function corsHandler(
    request: FastifyRequest,
    reply: any
  ) {
    const origin = request.headers.origin;

    // 验证 Origin
    if (origin && isOriginAllowed(origin, config.allowedOrigins)) {
      reply.header('Access-Control-Allow-Origin', origin);
    }

    // 设置其他 CORS 头
    reply.header('Access-Control-Allow-Methods', config.allowedMethods.join(', '));
    reply.header('Access-Control-Allow-Headers', config.allowedHeaders.join(', '));
    reply.header('Access-Control-Max-Age', config.maxAge.toString());

    if (config.credentials) {
      reply.header('Access-Control-Allow-Credentials', 'true');
    }

    // 处理预检请求
    if (request.method === 'OPTIONS') {
      reply.code(204).send();
      return;
    }
  };
}
```

