**任务 3.1: 实现 WebSocket JWT 认证**

优先级: 🔴 P0  
预计时间: 1 天  
负责人: 后端工程师

实施方案:
```typescript
// src/dashboard/middleware/websocket-auth.ts
import { WebSocket } from 'ws';
import jwt from 'jsonwebtoken';

interface AuthenticatedWebSocket extends WebSocket {
  userId?: string;
  isAuthenticated?: boolean;
}

interface WebSocketAuthConfig {
  jwtSecret: string;
  tokenExpiry: string;
  rateLimit: {
    windowMs: number;
    max: number;
  };
}

export class WebSocketAuthManager {
  private connections: Map<WebSocket, ConnectionInfo> = new Map();
  private rateLimiter: Map<string, RateLimitInfo> = new Map();

  constructor(private config: WebSocketAuthConfig) {}

  /**
   * 验证 WebSocket 连接
   */
  async authenticate(ws: AuthenticatedWebSocket, token?: string): Promise<boolean> {
    if (!token) {
      this.sendError(ws, 'Authentication required', 4001);
      return false;
    }

    try {
      // 验证 JWT
      const decoded = jwt.verify(token, this.config.jwtSecret) as {
        userId: string;
        permissions: string[];
      };

      // 检查速率限制
      if (!this.checkRateLimit(decoded.userId)) {
        this.sendError(ws, 'Rate limit exceeded', 4003);
        return false;
      }

      // 标记连接已认证
      ws.userId = decoded.userId;
      ws.isAuthenticated = true;

      this.connections.set(ws, {
        userId: decoded.userId,
        permissions: decoded.permissions,
        connectedAt: new Date(),
        lastActivity: new Date()
      });

      console.log(`[WebSocket] ✅ User authenticated: ${decoded.userId}`);
      return true;

    } catch (error) {
      this.sendError(ws, 'Invalid token', 4002);
      return false;
    }
  }

  /**
   * 检查权限
   */
  hasPermission(ws: AuthenticatedWebSocket, permission: string): boolean {
    const conn = this.connections.get(ws);
    if (!conn) return false;

    return conn.permissions.includes(permission) || 
           conn.permissions.includes('*');
  }

  /**
   * 速率限制检查
   */
  private checkRateLimit(userId: string): boolean {
    const now = Date.now();
    const limit = this.rateLimiter.get(userId);

    if (!limit) {
      this.rateLimiter.set(userId, {
        count: 1,
        resetAt: now + this.config.rateLimit.windowMs
      });
      return true;
    }

    // 重置计数器
    if (now > limit.resetAt) {
      limit.count = 1;
      limit.resetAt = now + this.config.rateLimit.windowMs;
      return true;
    }

    // 检查是否超限
    if (limit.count >= this.config.rateLimit.max) {
      return false;
    }

    limit.count++;
    return true;
  }

  /**
   * 发送错误消息
   */
  private sendError(ws: WebSocket, message: string, code: number): void {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({
        type: 'error',
        code,
        message
      }));
      ws.close(code);
    }
  }

  /**
   * 清理断开的连接
   */
  disconnect(ws: WebSocket): void {
    this.connections.delete(ws);
  }
}

interface ConnectionInfo {
  userId: string;
  permissions: string[];
  connectedAt: Date;
  lastActivity: Date;
}

interface RateLimitInfo {
  count: number;
  resetAt: number;
}
```

