```typescript
// ✅ 改进方案
export class SecureBaseAgent extends BaseAgent {
  protected permissionMode: PermissionMode = 'default'; // 改为默认模式

  // 白名单机制
  private allowedPaths: string[] = [
    process.cwd() + '/src',
    process.cwd() + '/tests'
  ];

  private forbiddenOperations: string[] = [
    'rm -rf',
    'format',
    'del /f',
    'DROP TABLE',
    'DELETE FROM'
  ];

  async *execute(prompt: string): AsyncGenerator<any> {
    // 1. 输入验证
    if (this.containsMaliciousInput(prompt)) {
      throw new SecurityError('检测到恶意输入');
    }

    // 2. 权限检查
    if (!this.isOperationAllowed(prompt)) {
      throw new PermissionError('操作未被授权');
    }

    // 3. 执行前确认
    if (this.requiresConfirmation(prompt)) {
      const confirmed = await this.requestConfirmation(prompt);
      if (!confirmed) {
        throw new OperationCancelledError('操作被用户取消');
      }
    }

    return super.execute(prompt);
  }

  private containsMaliciousInput(input: string): boolean {
    const maliciousPatterns = [
      /rm\s+-rf\s+\//,
      /DROP\s+TABLE/i,
      /DELETE\s+FROM.*WHERE.*1\s*=\s*1/i,
      /eval\s*\(/,
      /exec\s*\(/,
      /<script[^>]*>.*<\/script>/i
    ];

    return maliciousPatterns.some(pattern => pattern.test(input));
  }
}
```

