// 2. Pinia Store - 迭代状态管理
// src/dashboard/frontend/src/stores/iteration.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<Iteration[]>([])
  const currentIteration = ref<Iteration | null>(null)
  const loading = ref(false)

  // 计算属性
  const completedCount = computed(() => 
    iterations.value.filter(i => i.status === 'completed').length
  )

  const successRate = computed(() => {
    const completed = completedCount.value
    const failed = iterations.value.filter(i => i.status === 'failed').length
    const total = completed + failed
    return total > 0 ? ((completed / total) * 100).toFixed(1) : '0'
  })

  // Actions
  async function fetchIterations(params?: any) {
    loading.value = true
    try {
      const response = await apiClient.get('/iterations', { params })
      iterations.value = response.data
    } finally {
      loading.value = false
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    completedCount,
    successRate,
    fetchIterations
  }
})
