import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private iterationService?: any
  private realtimeService?: any

  async start() {
    // 初始化 Dashboard 服务
    if (config.enableDashboard) {
      const services = getServices()
      this.iterationService = services.iterationService
      this.realtimeService = services.realtimeService
    }

    while (this.running && this.shouldContinue()) {
      const iterationNum = this.iterationCount + 1

      // 创建迭代记录
      if (this.iterationService) {
        const iteration = await this.iterationService.createIteration({
          iterationNumber: iterationNum,
          status: 'running',
          requirement: this.requirement,
          startedAt: new Date()
        })

        // 广播迭代开始
        this.realtimeService?.broadcast('iteration.status_changed', {
          iterationId: iteration.id,
          iterationNumber: iterationNum,
          status: 'running',
          timestamp: new Date()
        })
      }

      // 执行产品经理 Agent
      this.notifyAgentStart('ProductManager')
      const pmResult = await this.productManager.execute(this.requirement)
      this.notifyAgentComplete('ProductManager', pmResult)

      // 执行架构师 Agent
      this.notifyAgentStart('Architect')
      const architectResult = await this.architect.execute(pmResult.output)
      this.notifyAgentComplete('Architect', architectResult)

      // ... 其他 Agent

      // 更新迭代状态
      if (this.iterationService) {
        await this.iterationService.updateIteration(iteration.id, {
          status: 'completed',
          completedAt: new Date()
        })
      }
    }
  }

  private notifyAgentStart(agentName: string) {
    this.realtimeService?.broadcast('agent.status_changed', {
      name: agentName,
      status: 'running',
      timestamp: new Date()
    })
  }

  private notifyAgentComplete(agentName: string, result: any) {
    this.realtimeService?.broadcast('agent.status_changed', {
      name: agentName,
      status: 'completed',
      output: result.output,
      executionTime: result.executionTime,
      timestamp: new Date()
    })
  }
}
