// 完善 src/dashboard/services/realtime.service.ts
export class RealtimeService {
  private clients: Set<WebSocket> = new Set()
  private subscriptions: Map<WebSocket, Set<string>> = new Map()

  subscribe(client: WebSocket, channel: string) {
    if (!this.subscriptions.has(client)) {
      this.subscriptions.set(client, new Set())
    }
    this.subscriptions.get(client)!.add(channel)
  }

  broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data, timestamp: new Date() })

    this.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message)
      }
    })
  }

  startHeartbeat() {
    setInterval(() => {
      this.broadcast('system.heartbeat', { timestamp: new Date() })
    }, 30000)
  }
}
