    }

    this.metrics.get(key)!.push({
      duration,
      tokens,
      timestamp: new Date()
    })
  }

  recordAPICall(endpoint: string, duration: number, success: boolean) {
    const key = `api.${endpoint}`
    if (!this.metrics.has(key)) {
      this.metrics.set(key, [])
    }

    this.metrics.get(key)!.push({
      duration,
      success,
      timestamp: new Date()
    })
  }

  getStats(key: string) {
    const records = this.metrics.get(key) || []

    return {
      count: records.length,
      avgDuration: records.reduce((sum, r) => sum + r.duration, 0) / records.length,
      successRate: records.filter(r => r.success).length / records.length
    }
  }
}
