#### 任务 2: 系统集成 - AutoIterationEngine 与 Dashboard 通信 🔴
**工作量**: 2-3 天 | **优先级**: 最高

**核心问题**: Dashboard 无法接收实时迭代数据

**解决方案**:

```typescript
// src/auto-iteration.ts 需要添加
import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices?: any;

  async initDashboard() {
    try {
      this.dashboardServices = getServices();
    } catch (e) {
      // Dashboard 未启动，忽略
    }
  }

  // 迭代开始时通知
  async notifyIterationStart(iteration: any) {
    if (!this.dashboardServices) return;

    await this.dashboardServices.iterationService.create({
      iterationNumber: iteration.count,
      status: 'running',
      requirement: iteration.requirement,
      startTime: new Date()
    });

    this.dashboardServices.realtimeService.broadcast('iteration.status_changed', {
      iterationId: iteration.id,
      status: 'running',
      timestamp: new Date()
    });
  }

  // Agent 状态变化时通知
  async notifyAgentStatus(agentName: string, status: string, progress: number) {
    if (!this.dashboardServices) return;

    this.dashboardServices.realtimeService.broadcast('agent.status_changed', {
      agentName,
      status,
      progress,
      timestamp: new Date()
    });
  }

  // 迭代进度更新
  async notifyProgress(phase: string, progress: number, message: string) {
    if (!this.dashboardServices) return;

    this.dashboardServices.realtimeService.broadcast('iteration.progress', {
      phase,
      progress,
      message,
      timestamp: new Date()
    });
  }
}
```

