**修复建议**:
```typescript
// ✅ 添加输入验证
import { ValueError } from '@/errors';

fastify.get('/iterations', async (request, reply) => {
  const query = request.query as any;

  // 验证page参数
  const page = parseInt(query.page);
  if (isNaN(page) || page < 1 || page > 10000) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Invalid page parameter', code: 'INVALID_INPUT' }
    });
  }

  // 验证limit参数
  const limit = parseInt(query.limit);
  if (isNaN(limit) || limit < 1 || limit > 100) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Limit must be between 1 and 100', code: 'INVALID_INPUT' }
    });
  }

  // 白名单验证sort字段
  const allowedSortFields = ['createdAt', 'duration', 'status'];
  const sort = query.sort;
  if (sort && !allowedSortFields.includes(sort)) {
    return reply.code(400).send({
      success: false,
      error: { message: 'Invalid sort field', code: 'INVALID_INPUT' }
    });
  }

  // 验证status枚举
  const allowedStatuses = ['running', 'completed', 'failed', 'cancelled'];
  const filter = query.status && allowedStatuses.includes(query.status)
    ? { status: query.status as IterationStatus }
    : undefined;

  const options = { page, limit, sort, filter };
  const result = iterationService.getList(options);
  return reply.send(result);
});
```

